initial_model.plantuml:
@startuml
class Student {
    - studentCode : String
}
class Course {
    - courseName : String
}
class Enrollment {
    - enrollmentDate : Date
}
class TeachingAssistant {
    - firstName : String
    - lastName : String
}
class Assignment {
    - details : String
    - responsibilities : String
}
class LabSection {
    - location : String
    - startTime : Time
    - endTime : Time
}
Student "1" -- "0..*"  Enrollment : EnrolledIn
Enrollment "1" -- "1"  Course : EnrolledCourse
TeachingAssistant "1" -- "0..*"  Assignment : AssistsWith
Assignment "1" -- "1"  Course : AssignedToCourse
Course "1" *-- "1..*"  LabSection
@enduml

